import collections

class TrieNode:
    def __init__(self):
        self.children = collections.defaultdict(TrieNode)
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            node = node.children[char]
        node.is_end_of_word = True

def character_stream(text: str):
    for char in text:
        yield char

def process_stream_with_trie(stream_gen, trie_obj, max_word_length=30):
    active_matches = [] # List of (TrieNode, current_prefix_chars_list)

    for char in stream_gen:
        new_active_matches = []

        # Extend existing active matches
        for node, current_prefix_chars in active_matches:
            if char in node.children:
                next_node = node.children[char]
                extended_prefix_chars = current_prefix_chars + [char]

                if len(extended_prefix_chars) <= max_word_length:
                    new_active_matches.append((next_node, extended_prefix_chars))
                    if next_node.is_end_of_word:
                        print(f"Found word: {''.join(extended_prefix_chars)}")

        # Start new potential matches from the current character
        if char in trie_obj.root.children:
            node = trie_obj.root.children[char]
            new_active_matches.append((node, [char]))
            if node.is_end_of_word:
                print(f"Found word: {char}")

        active_matches = new_active_matches

if __name__ == "__main__":
    my_trie = Trie()
    words_to_add = ["apple", "app", "apply", "banana", "band", "and", "a", "bandana", "the", "of"]
    for word in words_to_add:
        my_trie.insert(word)

    stream_text = "The application of bananas and apples and a band and bandana."
    stream = character_stream(stream_text.lower()) # Convert to lowercase for consistent matching

    process_stream_with_trie(stream, my_trie)
